const amqplib = require('amqplib');
const { Pool } = require('pg');

// RabbitMQ connection settings
const rabbitMqUrl = 'amqp://localhost';
const queueName = 'my_queue';

// PostgreSQL database connection settings
const dbHost = 'localhost';
const dbPort = 5432;
const dbUser = 'my_user';
const dbPassword = 'my_password';
const dbName = 'my_database';

async function connectToRabbitMq() {
    try {
        const conn = await amqplib.connect(rabbitMqUrl);
        const channel = await conn.createChannel();
        await channel.assertQueue(queueName, { durable: true });
        return { conn, channel };
    } catch (err) {
        console.error('Error connecting to RabbitMQ:', err);
        process.exit(1);
    }
}

async function consumeMessages({ conn, channel }) {
    try {
        const msg = await channel.get(queueName);
        if (!msg) {
            console.log('No messages in queue');
            return;
        }

        const messageContent = msg.content.toString();
        const messageType = JSON.parse(messageContent).type;

        switch (messageType) {
            case 'CREATE_USER':
                createUser(JSON.parse(messageContent));
                break;
            case 'UPDATE_USER':
                updateUser(JSON.parse(messageContent));
                break;
            default:
                console.log(`Unknown message type: ${messageType}`);
        }

        await channel.ack(msg);
    } catch (err) {
        console.error('Error consuming messages:', err);
    }
}

async function createUser(data) {
    const pool = new Pool({
        host: dbHost,
        port: dbPort,
        user: dbUser,
        password: dbPassword,
        database: dbName
    });

    try {
        const query = `INSERT INTO users (name, email) VALUES ($1, $2) RETURNING *`;
        const result = await pool.query(query, [data.name, data.email]);
        console.log('User created:', result.rows[0]);
    } catch (err) {
        console.error('Error creating user:', err);
    } finally {
        pool.end();
    }
}

async function updateUser(data) {
    const pool = new Pool({
        host: dbHost,
        port: dbPort,
        user: dbUser,
        password: dbPassword,
        database: dbName
    });

    try {
        const query = `UPDATE users SET name=$1, email=$2 WHERE id=$3 RETURNING *`;
        const result = await pool.query(query, [data.name, data.email, data.id]);
        console.log('User updated:', result.rows[0]);
    } catch (err) {
        console.error('Error updating user:', err);
    } finally {
        pool.end();
    }
}

async function main() {
    const { conn, channel } = await connectToRabbitMq();
    setInterval(async () => {
        await consumeMessages({ conn, channel });
    }, 1000); // Consume messages every second
}

main().catch((err) => console.error('Error:', err));